import type { Question } from "./questions";

export const CLINICAL_SPECIALTIES_QUESTIONS: Question[] = [
  // ── PAEDIATRICS (IDs 6901–6940) ─────────────────────────────────────────────

  // Developmental Milestones
  { id:6901, subject:"Paediatrics", stem:"A baby smiles spontaneously in response to a face for the first time. At what age does social smile normally appear?", options:["2 weeks","6 weeks","3 months","4 months"], answer:1, explanation:"Social smile (smiling in response to a face) normally appears at 6 weeks of age. It is one of the earliest social milestones assessed in Denver Developmental Screening Test (DDST)." },
  { id:6902, subject:"Paediatrics", stem:"At which age does a normal infant gain full head control (no head lag when pulled to sitting position)?", options:["2 months","3 months","4 months","6 months"], answer:1, explanation:"Head control (no head lag on pull-to-sit) is achieved by 3 months. At 3 months the infant can also hold head steady in sitting position. Head lag disappears by 4-5 months." },
  { id:6903, subject:"Paediatrics", stem:"A mother brings her 5-month-old infant who reaches out and grasps a toy rattle held in front of him. Which milestone is this?", options:["Palmar grasp","Reaches for objects","Pincer grasp","Transfers objects"], answer:1, explanation:"Reaching for objects (voluntary reach) appears at 4 months. Palmar grasp is a primitive reflex. Pincer grasp (thumb-finger opposition) appears at 9 months. Transfers appear at 6-7 months." },
  { id:6904, subject:"Paediatrics", stem:"Pincer grasp (fine prehension using tip of thumb and index finger) normally develops at:", options:["6 months","9 months","12 months","15 months"], answer:1, explanation:"Pincer grasp appears at 9 months along with standing with support. It is assessed in the fine motor domain of DDST and indicates mature corticospinal tract function." },
  { id:6905, subject:"Paediatrics", stem:"According to Denver Developmental Screening Test (DDST), independent walking (walks without support) is normally achieved by:", options:["9 months","12-13 months","15 months","18 months"], answer:1, explanation:"Walking independently occurs at 12-13 months. Stands with support at 9 months, cruises along furniture at 10-11 months, and walks independently by 12-13 months." },
  { id:6906, subject:"Paediatrics", stem:"A 2-year-old child says 'mama go' and 'want milk'. This corresponds to which language milestone?", options:["Single words","Two-word phrases","Three-word sentences","Full sentences"], answer:1, explanation:"Two-word phrases (combining two meaningful words) appear at 2 years of age. Single words with meaning appear at 12 months; three-word sentences at 3 years." },
  { id:6907, subject:"Paediatrics", stem:"A child sits independently without support for the first time. At what age does sitting without support normally appear?", options:["4 months","6 months","8 months","9 months"], answer:2, explanation:"Sitting with support occurs at 6 months; sitting without support occurs at 8 months in most milestones charts. Sits with support: 6 months is a key milestone in DDST." },
  { id:6908, subject:"Paediatrics", stem:"Which of the following is the MOST appropriate screening tool for developmental assessment of children in clinical practice?", options:["Griffiths Mental Development Scales","Denver Developmental Screening Test (DDST)","Bayley Scales of Infant Development","Gesell Developmental Schedule"], answer:1, explanation:"DDST (Denver II) is the most widely used screening tool for developmental delays in children 0-6 years. It assesses four domains: personal-social, fine motor, language, and gross motor. Griffiths and Bayley are diagnostic tools." },

  // IAP Immunization Schedule
  { id:6909, subject:"Paediatrics", stem:"As per IAP 2023 immunization schedule, BCG vaccine is given at:", options:["Birth","6 weeks","3 months","9 months"], answer:0, explanation:"BCG (Bacillus Calmette-Guérin) is given at birth as part of IAP 2023 schedule. It protects against severe forms of TB (miliary TB, TB meningitis) in infants. Single dose intradermally in right deltoid region." },
  { id:6910, subject:"Paediatrics", stem:"Which of the following vaccines is given at 9 months as per IAP 2023 immunization schedule?", options:["IPV","PCV10","MR vaccine","Varicella"], answer:2, explanation:"MR (measles-rubella) vaccine is given at 9 months (first dose) and at 16-24 months (second dose) per IAP 2023. PCV10 booster is at 9-12 months. IPV is at 6 and 14 weeks." },
  { id:6911, subject:"Paediatrics", stem:"As per IAP 2023 schedule, which vaccines are given at the 6-week visit? (Select the COMBINATION given)", options:["DPT + OPV + Hepatitis B + IPV + Rotavirus + PCV10","BCG + OPV + Hepatitis B","MR + Varicella + Typhoid","DPT + MMR + Typhoid + Hib"], answer:0, explanation:"At 6 weeks: DPT (1st dose) + OPV (1st dose) + Hepatitis B (2nd dose) + IPV (1st dose) + Rotavirus (1st dose) + PCV10 (1st dose) are given together per IAP 2023 schedule." },
  { id:6912, subject:"Paediatrics", stem:"As per IAP 2023, OPV (oral poliovirus vaccine) booster after the primary series is given at:", options:["6 months","9 months","12 months","16-24 months"], answer:1, explanation:"OPV booster is given at 9 months (combined with MR vaccine visit) per IAP 2023 schedule. The primary OPV series is at birth, 6, 10, and 14 weeks." },
  { id:6913, subject:"Paediatrics", stem:"Typhoid vaccine is introduced at what age in IAP 2023 immunization schedule?", options:["9 months","12 months","2 years","5 years"], answer:2, explanation:"Typhoid conjugate vaccine (TCV) is given at 2 years of age as per IAP 2023 schedule. It provides protection against Salmonella typhi infection which is common in India." },
  { id:6914, subject:"Paediatrics", stem:"Varicella (chickenpox) vaccine doses as per IAP 2023 schedule are given at:", options:["9 months and 16-24 months","15 months and 4-6 years","12 months only","6 months and 18 months"], answer:1, explanation:"Per IAP 2023, varicella vaccine is given at 15 months (1st dose) and 4-6 years (2nd dose). Two doses ensure >95% seroconversion and better breakthrough disease protection." },

  // Neonatal
  { id:6915, subject:"Paediatrics", stem:"APGAR score of 3 at 5 minutes after birth indicates:", options:["Normal newborn","Mild depression","Moderate depression","Severe depression requiring immediate resuscitation"], answer:3, explanation:"APGAR score 0-3 = severe depression requiring immediate and vigorous resuscitation. Score 4-6 = moderate depression; 7-10 = normal. APGAR assesses Activity (tone), Pulse, Grimace, Appearance (colour), and Respiration." },
  { id:6916, subject:"Paediatrics", stem:"In neonatal resuscitation, the FIRST step after delivery of a baby is:", options:["Positive pressure ventilation","Chest compressions","Provide warmth, dry and stimulate","Intubation and surfactant"], answer:2, explanation:"The initial steps of neonatal resuscitation (NRP) are: warmth → dry → stimulate → clear airway → assess. PPV is initiated if baby is gasping/apnoeic or HR <100/min after initial steps." },
  { id:6917, subject:"Paediatrics", stem:"In neonatal resuscitation, chest compressions are started when heart rate remains below what threshold after 30 seconds of adequate PPV?", options:["<100/min","<80/min","<60/min","<40/min"], answer:2, explanation:"Chest compressions are initiated when HR <60/min despite 30 seconds of effective positive pressure ventilation. Compressions are given at 3:1 ratio (3 compressions:1 breath) at rate 90 compressions+30 breaths/min." },
  { id:6918, subject:"Paediatrics", stem:"Physiological jaundice in a term neonate appears on day:", options:["1st day","2nd-3rd day","5th-7th day","After 14 days"], answer:1, explanation:"Physiological jaundice appears on day 2-3, peaks on day 4-5, and disappears by day 10 in term neonates. It is due to increased bilirubin production (fetal Hb breakdown), immature liver conjugation, and increased enterohepatic circulation." },
  { id:6919, subject:"Paediatrics", stem:"Which feature MOST strongly indicates pathological (non-physiological) jaundice in a neonate?", options:["Jaundice appearing on day 3","Total bilirubin 10 mg/dL on day 5","Jaundice appearing within 24 hours of birth","Jaundice disappearing by day 10"], answer:2, explanation:"Jaundice within first 24 hours of life is always pathological - think haemolytic disease (Rh/ABO incompatibility, G6PD deficiency, hereditary spherocytosis). Other pathological features: bilirubin rising >5 mg/dL/day, persisting beyond 2 weeks, direct bilirubin elevated." },
  { id:6920, subject:"Paediatrics", stem:"Most common causative organisms of neonatal meningitis (0-3 months) are:", options:["Streptococcus pneumoniae + H. influenzae","Group B Streptococcus (GBS) + E. coli","N. meningitidis + Listeria","Staphylococcus aureus + Pseudomonas"], answer:1, explanation:"Neonatal meningitis (0-3 months) is caused predominantly by Group B Streptococcus (GBS) and E. coli (both acquired from maternal genital tract). After 3 months: N. meningitidis, S. pneumoniae, H. influenzae." },

  // Malnutrition
  { id:6921, subject:"Paediatrics", stem:"Hallmark feature of Kwashiorkor that distinguishes it from Marasmus is:", options:["Severe muscle wasting","Pitting oedema","Old man facies","Weight <60% expected"], answer:1, explanation:"Pitting oedema (particularly of feet/legs) is the hallmark of Kwashiorkor (protein deficiency). Kwashiorkor = oedema + skin changes (flaky paint dermatosis) + hair changes (flag sign) + moon face + fatty liver. Marasmus has no oedema." },
  { id:6922, subject:"Paediatrics", stem:"'Flag sign' in the hair is a feature of:", options:["Marasmus","Iron deficiency anaemia","Kwashiorkor","Pellagra"], answer:2, explanation:"Flag sign (alternating bands of dark and light/depigmented hair) occurs in Kwashiorkor due to episodic protein deficiency. The light bands represent periods of protein deprivation. Also seen in hypothyroidism and severe malnutrition." },
  { id:6923, subject:"Paediatrics", stem:"Mid-upper arm circumference (MUAC) < 11.5 cm in a child aged 6-59 months indicates:", options:["Normal nutritional status","Mild acute malnutrition","Moderate acute malnutrition (MAM)","Severe acute malnutrition (SAM)"], answer:3, explanation:"MUAC interpretation in 6-59 months: <11.5 cm = SAM (red); 11.5-12.5 cm = MAM (yellow); >12.5 cm = normal (green). MUAC is easy to measure and predictive of mortality, used in community-based SAM screening." },
  { id:6924, subject:"Paediatrics", stem:"A severely malnourished child with oedema, apathy, moon face, and flaky paint dermatosis but weight only 75% of expected is diagnosed with:", options:["Marasmus","Marasmic Kwashiorkor","Kwashiorkor","Grade III PEM"], answer:2, explanation:"Kwashiorkor: protein deficiency with oedema + skin/hair changes + moon face + fatty liver + apathy. Weight may be normal/near-normal due to oedema masking wasting. Marasmus: severe wasting, no oedema, alert, weight <60%." },

  // Congenital Heart Disease
  { id:6925, subject:"Paediatrics", stem:"Most common congenital heart disease (CHD) overall is:", options:["Atrial septal defect (ASD)","Ventricular septal defect (VSD)","Patent ductus arteriosus (PDA)","Tetralogy of Fallot (TOF)"], answer:1, explanation:"VSD (perimembranous type, 70-80%) is the most common CHD overall accounting for 30-35% of all CHD. Most small VSDs close spontaneously. Large VSDs cause L→R shunt with Eisenmenger's syndrome risk." },
  { id:6926, subject:"Paediatrics", stem:"Tetralogy of Fallot (TOF) consists of all EXCEPT:", options:["Pulmonary stenosis","Ventricular septal defect","Overriding aorta","Atrial septal defect"], answer:3, explanation:"TOF consists of 4 features: (1) Pulmonary stenosis (RVOTO), (2) VSD, (3) Overriding aorta, (4) RV hypertrophy. ASD is not part of TOF. Mnemonic: PROVE (PS + RVH + Overriding aorta + VSD)." },
  { id:6927, subject:"Paediatrics", stem:"Boot-shaped heart on chest X-ray is characteristic of:", options:["Transposition of great arteries","Tetralogy of Fallot","Total anomalous pulmonary venous connection","ASD secundum"], answer:1, explanation:"Boot-shaped heart (coeur en sabot) in TOF is due to RVH (uplifted apex) + absent/small pulmonary artery segment + clear lung fields (oligaemic). TGA shows egg-on-string appearance on CXR." },
  { id:6928, subject:"Paediatrics", stem:"A cyanotic infant becomes less cyanosed in the squatting position. The MOST likely diagnosis is:", options:["Transposition of great arteries","ASD with Eisenmenger","Tetralogy of Fallot","Tricuspid atresia"], answer:2, explanation:"Squatting in TOF increases systemic vascular resistance (compresses femoral arteries), reducing R→L shunting across VSD and increasing pulmonary blood flow, thus relieving cyanosis. It is pathognomonic of TOF." },
  { id:6929, subject:"Paediatrics", stem:"Most common cyanotic CHD presenting at BIRTH (in the neonatal period) is:", options:["Tetralogy of Fallot","Tricuspid atresia","Transposition of great arteries (TGA)","Pulmonary atresia"], answer:2, explanation:"TGA is the most common cyanotic CHD presenting at birth with severe cyanosis (aorta from RV + PA from LV → two parallel circuits). TOF is the most common cyanotic CHD after the first year of life." },
  { id:6930, subject:"Paediatrics", stem:"Egg-on-a-string appearance on CXR with severe cyanosis at birth is diagnostic of:", options:["Tetralogy of Fallot","Transposition of great arteries","TAPVC","Truncus arteriosus"], answer:1, explanation:"TGA: egg-on-side/egg-on-string appearance is due to narrow mediastinum (great vessels lying parallel rather than crossing) + cardiomegaly. Severe cyanosis from birth that doesn't respond to O2 = TGA until proven otherwise." },

  // Infections
  { id:6931, subject:"Paediatrics", stem:"Koplik spots (white spots on buccal mucosa opposite lower molars) are pathognomonic of:", options:["Rubella","Measles","Herpangina","Kawasaki disease"], answer:1, explanation:"Koplik spots appear 1-2 days before the measles rash and persist for 2-3 days. They are pathognomonic of measles (rubeola), caused by Morbillivirus. Rash appears day 3-5 as maculopapular from face downwards." },
  { id:6932, subject:"Paediatrics", stem:"Most common cause of death in measles is:", options:["Encephalitis","Pneumonia","Subacute sclerosing panencephalitis (SSPE)","Myocarditis"], answer:1, explanation:"Pneumonia (bacterial superinfection - S. pneumoniae, Staphylococcus, or measles giant cell pneumonia) is the most common cause of death in measles. SSPE is a rare late complication (7-10 years later). Encephalitis occurs in 1:1000 cases." },
  { id:6933, subject:"Paediatrics", stem:"Culture medium used for isolation of Bordetella pertussis (whooping cough) is:", options:["Löwenstein-Jensen medium","Bordet-Gengou medium","TCBS agar","Chocolate agar"], answer:1, explanation:"Bordet-Gengou medium (potato-blood-glycerol agar) is used for culture of Bordetella pertussis. Löwenstein-Jensen is for Mycobacterium tuberculosis. TCBS is for Vibrio cholerae." },
  { id:6934, subject:"Paediatrics", stem:"Drug of choice for treatment of pertussis (whooping cough) is:", options:["Penicillin","Amoxicillin","Azithromycin","Cotrimoxazole"], answer:2, explanation:"Azithromycin is the drug of choice for pertussis (especially in infants <1 month where erythromycin causes pyloric stenosis risk). Azithromycin 10 mg/kg/day for 5 days eliminates organism and reduces transmission." },
  { id:6935, subject:"Paediatrics", stem:"A neonate presents with fever, bulging fontanelle, and seizures. CSF shows neutrophilic pleocytosis, low glucose, and high protein. Which organism is MOST likely?", options:["Streptococcus pneumoniae","Group B Streptococcus","Neisseria meningitidis","Listeria monocytogenes"], answer:1, explanation:"Group B Streptococcus (GBS) is the most common cause of neonatal meningitis (0-3 months). CSF in bacterial meningitis: neutrophilic pleocytosis, low glucose (<40% of blood glucose), elevated protein (>150 mg/dL in neonates)." },

  // Mixed Paediatrics
  { id:6936, subject:"Paediatrics", stem:"A child presents with inspiratory stridor, barking cough, and low-grade fever. X-ray shows 'steeple sign'. The MOST likely diagnosis is:", options:["Epiglottitis","Croup (laryngotracheobronchitis)","Foreign body aspiration","Bacterial tracheitis"], answer:1, explanation:"Croup (viral laryngotracheobronchitis - parainfluenza virus) causes barking cough + inspiratory stridor + steeple sign (subglottic narrowing on AP neck X-ray). Epiglottitis shows thumb/thumbprint sign on lateral neck X-ray." },
  { id:6937, subject:"Paediatrics", stem:"A 3-year-old presents with swallowing difficulty, drooling, and high fever. He sits in a 'sniffing' position. Lateral neck X-ray shows 'thumbprint' sign. The MOST likely diagnosis is:", options:["Croup","Epiglottitis","Retropharyngeal abscess","Foreign body"], answer:1, explanation:"Epiglottitis (H. influenzae type b, now rare post-Hib vaccine): high fever + drooling + dysphagia + sitting in tripod/sniffing position (airway stabilisation). Thumbprint sign on lateral X-ray = swollen epiglottis. Emergency airway management." },
  { id:6938, subject:"Paediatrics", stem:"Which of the following is the MOST common cause of acute diarrhoea in children under 5 years worldwide?", options:["Enterotoxigenic E. coli","Rotavirus","Salmonella typhi","Giardia lamblia"], answer:1, explanation:"Rotavirus is the most common cause of severe dehydrating diarrhoea in children <5 years globally. It causes watery (non-bloody) diarrhoea with vomiting. Rotavirus vaccine in IAP 2023 schedule at 6, 10, 14 weeks." },
  { id:6939, subject:"Paediatrics", stem:"In a child with severe dehydration due to acute gastroenteritis, the FIRST priority is:", options:["Oral rehydration solution (ORS)","IV Ringer's lactate or normal saline bolus","Antibiotic therapy","Zinc supplementation"], answer:1, explanation:"Severe dehydration (lethargy, sunken eyes, skin pinch >2 sec, unable to drink) requires immediate IV rehydration: Ringer's lactate (or NS) 100 mL/kg over 3 hours (child >1 month). ORS is for mild-moderate dehydration." },
  { id:6940, subject:"Paediatrics", stem:"Subacute sclerosing panencephalitis (SSPE) is a late complication of measles occurring typically:", options:["2-4 weeks after measles","3-6 months after measles","2-12 years after measles","Only in immunocompromised children"], answer:2, explanation:"SSPE is a progressive fatal encephalitis caused by persistent defective measles virus in CNS, occurring 7-10 years (range 2-12 years) after measles infection. Features: personality change → myoclonic jerks → dementia → death. EEG: periodic complexes." },

  // ── PSM/COMMUNITY MEDICINE (IDs 6941–6980) ──────────────────────────────────

  // Biostatistics
  { id:6941, subject:"PSM/Community Medicine", stem:"A screening test has sensitivity 90% and specificity 80%. This means:", options:["It detects 80% of true cases and has 90% false positives","It correctly identifies 90% of diseased people and 80% of non-diseased people","It has 90% PPV and 80% NPV","Both positive and negative predictive values are 85%"], answer:1, explanation:"Sensitivity = TP/(TP+FN) = 90% means 90% of truly diseased are correctly identified (true positive rate). Specificity = TN/(TN+FP) = 80% means 80% of truly non-diseased are correctly identified (true negative rate). Sensitivity is used for screening; specificity for confirmation." },
  { id:6942, subject:"PSM/Community Medicine", stem:"For SCREENING a disease, we prefer a test with:", options:["High specificity and low sensitivity","High sensitivity and low specificity","Equal sensitivity and specificity","High PPV regardless of sensitivity/specificity"], answer:1, explanation:"Screening tests should have HIGH SENSITIVITY to miss few true cases (maximize TP, minimize FN). A high-sensitivity test with negative result effectively rules OUT disease (SnNout). High-specificity tests are preferred for CONFIRMATION (SpPin - rules in disease)." },
  { id:6943, subject:"PSM/Community Medicine", stem:"Positive predictive value (PPV) of a screening test INCREASES when:", options:["Disease prevalence decreases","Disease prevalence increases","Sensitivity decreases","Specificity decreases"], answer:1, explanation:"PPV = TP/(TP+FP). As disease prevalence increases, more true positives occur relative to false positives, raising PPV. Low prevalence → many false positives → low PPV (even with excellent specificity). This is why mass screening has lower PPV." },
  { id:6944, subject:"PSM/Community Medicine", stem:"In a clinical trial, the control event rate (CER) is 20% and the experimental event rate (EER) is 12%. The Number Needed to Treat (NNT) is:", options:["5","10","12.5","8.3"], answer:2, explanation:"ARR (Absolute Risk Reduction) = CER - EER = 20% - 12% = 8% = 0.08. NNT = 1/ARR = 1/0.08 = 12.5. NNT is the number of patients you need to treat to prevent one additional bad outcome." },
  { id:6945, subject:"PSM/Community Medicine", stem:"Likelihood ratio positive (LR+) is calculated as:", options:["Sensitivity × Specificity","Sensitivity / (1 - Specificity)","(1 - Sensitivity) / Specificity","Specificity / (1 - Sensitivity)"], answer:1, explanation:"LR+ = Sensitivity/(1-Specificity) = TPR/FPR. LR+ >10 is strong evidence to rule in disease; LR+ <0.1 rules out. LR+ indicates how much a positive test result increases the probability of disease." },
  { id:6946, subject:"PSM/Community Medicine", stem:"Odds Ratio (OR) as a measure of association is used in which study design?", options:["Randomized controlled trial","Cohort study","Case-control study","Cross-sectional study"], answer:2, explanation:"OR is calculated in case-control studies: OR = (cases exposed / cases unexposed) / (controls exposed / controls unexposed). In RCT and cohort studies, Relative Risk (RR) is the preferred measure. OR approximates RR when disease is rare." },
  { id:6947, subject:"PSM/Community Medicine", stem:"Relative Risk (RR) of 1.0 in a cohort study means:", options:["Exposure doubles the risk","Exposure halves the risk","Exposure has no association with disease","100% risk in exposed group"], answer:2, explanation:"RR = risk in exposed / risk in unexposed. RR=1: no association; RR>1: positive association (risk factor); RR<1: negative association (protective). RR is used in cohort studies and RCTs (can calculate incidence in both groups)." },

  // Study Designs
  { id:6948, subject:"PSM/Community Medicine", stem:"Gold standard study design to establish causation between an intervention and outcome is:", options:["Prospective cohort study","Meta-analysis of observational studies","Randomised controlled trial (RCT)","Case-control study"], answer:2, explanation:"RCT is the gold standard for establishing causality because: randomisation controls confounding (known and unknown), blinding reduces bias (performance, detection bias), controlled conditions isolate intervention effect. Meta-analysis of RCTs is highest in evidence hierarchy." },
  { id:6949, subject:"PSM/Community Medicine", stem:"Which study design is BEST for studying rare diseases?", options:["Cohort study","RCT","Cross-sectional study","Case-control study"], answer:3, explanation:"Case-control study: starts with cases (diseased) and controls (non-diseased), then looks back for exposure. Ideal for rare diseases because cases are selected first. Cohort studies would need huge sample sizes and long follow-up to accumulate rare disease cases." },
  { id:6950, subject:"PSM/Community Medicine", stem:"Recall bias is a major limitation of which study design?", options:["RCT","Cohort study","Case-control study","Ecological study"], answer:2, explanation:"Recall bias in case-control studies: cases (diseased) tend to remember past exposures more clearly than controls (non-diseased), overestimating the association. Also causes Berkson's bias (hospital-based selection) and interviewer bias." },
  { id:6951, subject:"PSM/Community Medicine", stem:"A study measures disease prevalence and exposure status at the same point in time. This design is called:", options:["Cohort study","Case-control study","Cross-sectional study","Ecological study"], answer:2, explanation:"Cross-sectional study (prevalence study) measures disease and exposure simultaneously. It gives prevalence but NOT incidence. Cannot establish temporality (which came first). Good for planning health services. Subject to prevalence-incidence bias (Neyman bias)." },
  { id:6952, subject:"PSM/Community Medicine", stem:"Berkson's bias is most likely to occur in:", options:["Community-based RCTs","Hospital-based case-control studies","Prospective cohort studies","Cross-sectional surveys"], answer:1, explanation:"Berkson's bias: when both exposure and disease independently increase probability of hospital admission, hospital cases show spurious association with exposure (cases and controls not representative of general population). Classic in hospital-based case-control studies." },

  // Epidemiology
  { id:6953, subject:"PSM/Community Medicine", stem:"Shortest incubation period among the following is:", options:["Typhoid (7-21 days)","Staphylococcal food poisoning (2-6 hours)","Hepatitis A (15-50 days)","Cholera (2-3 days)"], answer:1, explanation:"Staphylococcal food poisoning has the shortest incubation (2-6 hours) because S. aureus pre-formed heat-stable enterotoxin acts directly without organism multiplication in host. Salmonella: 12-36h; Cholera: 2h-5 days (usually 2-3 days); Typhoid: 1-3 weeks." },
  { id:6954, subject:"PSM/Community Medicine", stem:"Secondary attack rate (SAR) is defined as:", options:["Number of new cases / Total population × 100","New cases among contacts / Total susceptible contacts × 100","Total cases / Time period × 100","Incidence in secondary cases / Primary incidence × 100"], answer:1, explanation:"SAR = (new cases among contacts within incubation period) / (total susceptible household contacts) × 100. SAR measures transmissibility within exposed groups. Higher SAR = more contagious. Measles SAR ~75-90%; Ebola ~5-25%." },
  { id:6955, subject:"PSM/Community Medicine", stem:"Generation time in epidemiology is defined as:", options:["Time from onset of symptoms to peak infectivity","Average interval between infection in primary and secondary cases","Time taken for a case to recover","Duration of the infectious period"], answer:1, explanation:"Generation time = average time between onset of illness in primary case and onset in secondary case infected by that primary. It reflects intrinsic transmissibility. Serial interval is the observed time between symptom onsets in successive cases (more easily measured)." },
  { id:6956, subject:"PSM/Community Medicine", stem:"Incubation period of hepatitis A is:", options:["2-6 hours","2-10 days","15-50 days","60-180 days"], answer:2, explanation:"Hepatitis A incubation: 15-50 days (average 28-30 days). Hepatitis B: 40-160 days. Hepatitis C: 15-150 days. Hepatitis E: 15-60 days. HAV spreads via fecal-oral route; most infectious during incubation/prodrome period." },
  { id:6957, subject:"PSM/Community Medicine", stem:"Attack rate is calculated as:", options:["Number ill / Number exposed × 100","Number ill / Total population × 100","Number of deaths / Number ill × 100","Number of cases / Person-years of observation"], answer:0, explanation:"Attack rate = (number who became ill) / (number exposed) × 100. It is used in outbreak investigations (not a true rate but a proportion). Case fatality rate = deaths/cases × 100. Incidence rate = new cases/person-time at risk." },

  // National Health Programs
  { id:6958, subject:"PSM/Community Medicine", stem:"India's target year for TB elimination (achieving <1 case per million population) under NTEP is:", options:["2023","2025","2030","2035"], answer:1, explanation:"India's National TB Elimination Programme (NTEP, formerly RNTCP) targets TB elimination by 2025 - 5 years ahead of the global SDG target of 2030. TB-mukt Bharat. Key initiative: Nikshay Poshan Yojana (Rs 500/month nutritional support to TB patients)." },
  { id:6959, subject:"PSM/Community Medicine", stem:"Nikshay Poshan Yojana provides monthly nutritional support of __ to all TB patients notified under NTEP:", options:["Rs 200","Rs 500","Rs 1000","Rs 2000"], answer:1, explanation:"Nikshay Poshan Yojana: Rs 500/month direct benefit transfer (DBT) to all TB patients (both public and private sector) notified under NTEP for nutritional support during treatment. Part of India's TB elimination strategy." },
  { id:6960, subject:"PSM/Community Medicine", stem:"BPaLM regimen for pre-XDR/XDR TB does NOT include:", options:["Bedaquiline","Pretomanid","Linezolid","Rifampicin"], answer:3, explanation:"BPaLM = Bedaquiline + Pretomanid + Linezolid + Moxifloxacin. This 6-month all-oral regimen is WHO-recommended for pre-XDR TB (rifampicin-resistant + fluoroquinolone-resistant). Rifampicin is NOT part of BPaLM; it is used in drug-sensitive TB (HRZE regimen)." },
  { id:6961, subject:"PSM/Community Medicine", stem:"First-line treatment of uncomplicated Plasmodium falciparum malaria in India as per NVBDCP is:", options:["Chloroquine + Primaquine","Artemether-Lumefantrine (ACT)","Quinine + Doxycycline","Mefloquine alone"], answer:1, explanation:"For P. falciparum: Artemisinin-based Combination Therapy (ACT) = Artemether-Lumefantrine for 3 days, used because of widespread chloroquine resistance. P. vivax: Chloroquine 3 days + Primaquine 14 days (radical cure). NVBDCP guidelines." },
  { id:6962, subject:"PSM/Community Medicine", stem:"First-line oral treatment for visceral leishmaniasis (kala-azar) in India is:", options:["Sodium stibogluconate (SSG)","Amphotericin B","Miltefosine","Paromomycin"], answer:2, explanation:"Miltefosine (oral, 28 days) is the first-line treatment for kala-azar in India under NVBDCP. It replaced SSG due to widespread resistance. Miltefosine is contraindicated in pregnancy. Single-dose liposomal amphotericin B is preferred in some settings." },
  { id:6963, subject:"PSM/Community Medicine", stem:"Mass drug administration (MDA) for lymphatic filariasis in India uses:", options:["DEC alone","DEC + Albendazole","Ivermectin + Albendazole","DEC + Ivermectin + Albendazole (IDA)"], answer:1, explanation:"India's NVBDCP filariasis MDA: DEC + Albendazole annually in endemic districts. Triple drug therapy (IDA = Ivermectin + DEC + Albendazole) is now WHO-recommended for accelerated elimination where onchocerciasis is not co-endemic." },
  { id:6964, subject:"PSM/Community Medicine", stem:"PM-JAY (Pradhan Mantri Jan Arogya Yojana) under Ayushman Bharat provides health insurance coverage of:", options:["Rs 1 lakh/family/year","Rs 5 lakh/family/year","Rs 10 lakh/family/year","Rs 50,000/individual/year"], answer:1, explanation:"PM-JAY provides Rs 5 lakh/family/year for hospitalisation (secondary and tertiary care) to approximately 10.74 crore poor and vulnerable families (bottom 40%). Cashless, paperless treatment at empanelled public and private hospitals." },
  { id:6965, subject:"PSM/Community Medicine", stem:"Health and Wellness Centres (HWCs) are an integral component of which national program?", options:["NRHM","NHM alone","Ayushman Bharat","RMNCH+A"], answer:2, explanation:"Health and Wellness Centres (HWCs) are the primary care pillar of Ayushman Bharat (2018), upgraded from existing Sub-Centres and PHCs. They provide comprehensive primary health care including mental health, palliative care, elderly care, and NCD screening." },

  // Healthcare System
  { id:6966, subject:"PSM/Community Medicine", stem:"As per rural health infrastructure norms, a Sub-Centre caters to a population of __ in plain areas:", options:["1,000","3,000","5,000","10,000"], answer:2, explanation:"Sub-Centre: 1 per 5,000 population in plains, 1 per 3,000 in hilly/tribal/difficult areas. Staffed by ANM (Auxiliary Nurse Midwife) + Male Health Worker. First contact point between community and health system." },
  { id:6967, subject:"PSM/Community Medicine", stem:"A Primary Health Centre (PHC) serves a population of __ in plains and has __ beds:", options:["5,000 population, 2 beds","10,000 population, 6 beds","30,000 population, 4-6 beds","50,000 population, 10 beds"], answer:2, explanation:"PHC: 1 per 30,000 population in plains, 1 per 20,000 in hilly areas. Has 4-6 beds and is staffed by a Medical Officer with paramedical staff. Provides preventive, promotive, and curative services. Refers to CHC for specialist care." },
  { id:6968, subject:"PSM/Community Medicine", stem:"Community Health Centre (CHC) is designated as the First Referral Unit (FRU) with __ beds and serves a population of:", options:["10 beds, 30,000 population","30 beds, 80,000-1.2 lakh population","50 beds, 2 lakh population","100 beds, 5 lakh population"], answer:1, explanation:"CHC: 1 per 80,000-1.2 lakh population, 30 beds, has specialists in surgery, medicine, OBG, paediatrics + anaesthesia. Designated FRU provides emergency obstetric care, blood transfusion, and essential surgical services." },
  { id:6969, subject:"PSM/Community Medicine", stem:"ASHA (Accredited Social Health Activist) is recruited at a ratio of:", options:["1 per 500 population","1 per 1,000 population","1 per 2,000 population","1 per village regardless of population"], answer:1, explanation:"ASHA: 1 per 1,000 population in rural areas under NRHM/NHM. She is a female community health volunteer (8th standard educated), acts as a link between community and health system, and receives performance-based incentives." },
  { id:6970, subject:"PSM/Community Medicine", stem:"OPV (oral polio vaccine) is stored at -20°C at which level of cold chain in India?", options:["Sub-centre level","PHC level","District vaccine store level","State vaccine store level"], answer:2, explanation:"OPV is stored at -20°C (deep freeze) at Regional/District Vaccine Store level. At PHC and CHC level: 2-8°C (ice-lined refrigerators). All other vaccines (DPT, measles, BCG, Hep B) are stored at 2-8°C throughout the cold chain." },

  // Additional PSM Topics
  { id:6971, subject:"PSM/Community Medicine", stem:"Which level of prevention does immunization represent?", options:["Primordial prevention","Primary prevention","Secondary prevention","Tertiary prevention"], answer:1, explanation:"Immunization is PRIMARY PREVENTION (protecting susceptible individuals from developing disease). Primordial: prevents risk factors. Secondary: early detection/screening. Tertiary: rehabilitation. Chemoprophylaxis is also primary prevention." },
  { id:6972, subject:"PSM/Community Medicine", stem:"The 'iceberg phenomenon' in epidemiology refers to:", options:["Majority of cases being severe and visible","Most cases in a community being subclinical/undiagnosed","Disease being rare but highly fatal","Tip of iceberg representing total disease burden"], answer:1, explanation:"Iceberg phenomenon: tip above water = diagnosed/clinical cases; submerged mass = subclinical, undiagnosed, latent cases (majority). Important in diseases like TB, diabetes, hypertension - clinical cases underestimate true burden." },
  { id:6973, subject:"PSM/Community Medicine", stem:"Herd immunity threshold for measles (R0 = 12-18) is approximately:", options:["50-60%","70-80%","90-95%","99%"], answer:2, explanation:"Herd immunity threshold = 1 - 1/R0. For measles R0 ≈ 15: threshold = 1 - 1/15 ≈ 93%. Requires >93-95% population immunity for interruption of transmission. This is why 2-dose MR schedule is essential to achieve high coverage." },
  { id:6974, subject:"PSM/Community Medicine", stem:"A study that collects data at a single point in time and measures both exposure and disease status is best described as:", options:["Cohort study","Case-control study","Cross-sectional study","Longitudinal study"], answer:2, explanation:"Cross-sectional study = prevalence study. Both exposure and outcome measured simultaneously. Cannot determine temporal sequence (which came first). Suitable for planning health services, measuring prevalence of chronic conditions, developing hypotheses." },
  { id:6975, subject:"PSM/Community Medicine", stem:"In epidemiology, 'endemic' refers to:", options:["Sudden increase in disease cases above expected baseline","Constant presence of disease in a community at expected levels","Disease occurring across multiple countries/continents","No cases of disease in a region"], answer:1, explanation:"Endemic: constant presence of disease at expected (baseline) levels in a defined population. Epidemic: cases significantly above expected baseline. Pandemic: epidemic across multiple countries. Hyperendemic: consistently high levels." },
  { id:6976, subject:"PSM/Community Medicine", stem:"Maternal mortality ratio (MMR) is expressed as:", options:["Deaths per 1,000 live births","Deaths per 100,000 live births","Deaths per 1,000 women of reproductive age","Deaths per 100 deliveries"], answer:1, explanation:"MMR = (maternal deaths during pregnancy/childbirth/42 days post-partum) / (total live births) × 100,000. India's MMR was 97/100,000 live births (SRS 2018-20). SDG target: <70 per 100,000 live births by 2030." },
  { id:6977, subject:"PSM/Community Medicine", stem:"Under-5 mortality rate (U5MR) is defined as:", options:["Deaths in children <5 years per 1,000 births in same year","Probability of dying between birth and age 5 per 1,000 live births","Deaths in children <5 years per 1,000 children under 5","Deaths in first month per 1,000 live births"], answer:1, explanation:"U5MR = probability of dying between birth and exactly 5 years of age per 1,000 live births. India's U5MR = 32 per 1,000 live births (SRS 2020). Infant mortality rate (IMR) = deaths in first year per 1,000 live births." },
  { id:6978, subject:"PSM/Community Medicine", stem:"The MOST important route of transmission of cholera is:", options:["Airborne droplets","Faecal-oral via contaminated water/food","Direct contact with cases","Vector-borne via mosquitoes"], answer:1, explanation:"Cholera (Vibrio cholerae O1/O139) spreads via faecal-oral route, predominantly through contaminated water. Incubation 2-3 days (range 2h-5 days). Rice-water stools. ORS treatment. Prevention: safe water, sanitation, Oral Cholera Vaccine (OCV)." },
  { id:6979, subject:"PSM/Community Medicine", stem:"Which of the following is the CORRECT denominator for calculating infant mortality rate (IMR)?", options:["Total population","Total number of births (live + still)","Live births in the same year","Total children under 1 year"], answer:2, explanation:"IMR = (deaths in infants <1 year in a year) / (live births in same year) × 1,000. NOT total births (excludes stillbirths). India's IMR = 27 per 1,000 live births (SRS 2020). Neonatal mortality (0-28 days) contributes ~70% of IMR." },
  { id:6980, subject:"PSM/Community Medicine", stem:"Integrated Child Development Services (ICDS) scheme is implemented through:", options:["ASHA workers","Auxiliary Nurse Midwife (ANM)","Anganwadi Workers (AWW)","Community Health Officers (CHO)"], answer:2, explanation:"ICDS is implemented through Anganwadi Workers (AWW) based at Anganwadi Centres (AWC). AWW provides supplementary nutrition, immunization, health check-up, referral, pre-school education, and nutrition/health education to children 0-6 years + pregnant/lactating women." },

  // ── ENT/OPHTHALMOLOGY (IDs 6981–7005) ─────────────────────────────────────

  // ENT - CSOM
  { id:6981, subject:"ENT/Ophthalmology", stem:"A patient with chronic ear discharge has a large central perforation on otoscopy. The discharge is mucoid, non-foul smelling, and there is no cholesteatoma. This is classified as:", options:["CSOM unsafe type (atticoantral)","CSOM safe type (tubotympanic)","Otitis externa","Acute suppurative otitis media"], answer:1, explanation:"CSOM tubotympanic (safe type): central/large perforation in pars tensa, mucopurulent non-foul discharge, NO cholesteatoma, NO dangerous complications. Treated medically (ear toilet + topical antibiotics). Myringoplasty for dry perforation." },
  { id:6982, subject:"ENT/Ophthalmology", stem:"Which of the following features in CSOM indicates UNSAFE (dangerous) disease requiring urgent surgery?", options:["Central perforation with mucopurulent discharge","Bilateral ear disease","Hearing loss of 30 dB","Facial nerve palsy or vertigo"], answer:3, explanation:"CSOM unsafe (atticoantral) = cholesteatoma. Dangerous signs indicating cholesteatoma/complications: facial nerve palsy, vertigo, intracranial extension. Also: marginal/attic perforation, foul-smelling discharge, granulations. Requires mastoidectomy." },
  { id:6983, subject:"ENT/Ophthalmology", stem:"In Rinne's test, a 'negative Rinne' (BC > AC) indicates:", options:["Normal hearing","Sensorineural hearing loss","Conductive hearing loss","Mixed hearing loss"], answer:2, explanation:"Rinne's test: BC (bone conduction by mastoid) vs AC (air conduction by outside ear). Normal (positive Rinne): AC > BC. Negative Rinne (BC > AC): Conductive Hearing Loss (CHL) - sound bypasses blocked external/middle ear. In SNHL: Rinne remains positive (both reduced equally)." },
  { id:6984, subject:"ENT/Ophthalmology", stem:"In Weber's test, the sound lateralises to the WORSE ear in:", options:["Sensorineural hearing loss","Conductive hearing loss","Bilateral equal SNHL","Normal hearing"], answer:1, explanation:"Weber lateralises to WORSE ear in CHL (bone conduction enhanced in affected ear due to masking effect, and absent ambient noise effect). Weber lateralises to BETTER ear in unilateral SNHL (cochlea is better functioning). Midline = normal or bilateral symmetric loss." },
  { id:6985, subject:"ENT/Ophthalmology", stem:"Tympanogram Type B (flat tympanogram) is seen in:", options:["Normal middle ear","Eustachian tube dysfunction with negative middle ear pressure","Middle ear effusion or tympanic membrane perforation","Otosclerosis"], answer:2, explanation:"Tympanogram: Type A = normal; Type As = reduced compliance (otosclerosis/tympanosclerosis); Type Ad = hypercompliance (ossicular discontinuity); Type B = flat/no peak (middle ear effusion, TM perforation, or grommet); Type C = negative pressure peak (ETD)." },
  { id:6986, subject:"ENT/Ophthalmology", stem:"BERA (Brainstem Evoked Response Audiometry) is preferred for hearing assessment in:", options:["Adults with SNHL","Cooperative children over 5 years","Infants and medico-legal cases","Patients with conductive hearing loss only"], answer:2, explanation:"BERA/ABR is objective (does not require cooperation), hence ideal for infants, young children, and medico-legal cases. It measures brainstem electrical potentials in response to clicks. Normal interpeak latency I-III-V. OAE is used for neonatal screening." },
  { id:6987, subject:"ENT/Ophthalmology", stem:"Furunculosis of the external auditory canal is caused by:", options:["Pseudomonas aeruginosa","Staphylococcus aureus","Aspergillus niger","Streptococcus pyogenes"], answer:1, explanation:"Furunculosis (boil in outer 1/3 of EAC where hair follicles present) is caused by Staphylococcus aureus. Key feature: extreme pain on moving pinna or pressing tragus (differentiates from otitis media). Treatment: incision + drainage + flucloxacillin." },

  // Ophthalmology - Glaucoma
  { id:6988, subject:"ENT/Ophthalmology", stem:"Primary open-angle glaucoma (POAG) characteristically presents with:", options:["Acute painful red eye with nausea/vomiting","Insidious painless bilateral vision loss with elevated IOP","Mid-dilated fixed pupil and corneal oedema","Sudden unilateral visual loss with no pain"], answer:1, explanation:"POAG: chronic, insidious, painless, bilateral. Elevated IOP >21 mmHg, open angle on gonioscopy, optic disc changes (C:D ratio >0.6, notching, disc haemorrhage), arcuate/Bjerrum scotoma. Treated with topical prostaglandin analogues (first-line: latanoprost)." },
  { id:6989, subject:"ENT/Ophthalmology", stem:"Cup-to-disc (C:D) ratio threshold for suspicion of glaucomatous optic neuropathy is:", options:["C:D > 0.3","C:D > 0.5","C:D > 0.6","C:D > 0.8"], answer:2, explanation:"Normal C:D ratio ≤ 0.4; ratio >0.6 or asymmetry >0.2 between eyes is suspicious for glaucoma. Progressive increase in C:D ratio (cupping) indicates optic nerve damage. Other features: notching at inferior>superior pole (ISNT rule violated), disc haemorrhage." },
  { id:6990, subject:"ENT/Ophthalmology", stem:"A patient presents with acute red eye, severe pain, nausea, vomiting, and blurred vision. Examination shows mid-dilated fixed pupil and hazy cornea. The MOST likely diagnosis is:", options:["Primary open-angle glaucoma","Anterior uveitis (iridocyclitis)","Primary angle-closure glaucoma (PACG)","Corneal ulcer"], answer:2, explanation:"PACG (acute): sudden severe pain, photophobia, blurred vision, haloes, nausea/vomiting, conjunctival congestion, corneal oedema (hazy), mid-dilated fixed non-reactive pupil, shallow anterior chamber. Emergency: IV acetazolamide + pilocarpine + topical beta-blocker, then laser iridotomy." },
  { id:6991, subject:"ENT/Ophthalmology", stem:"First-line topical medication for primary open-angle glaucoma (POAG) to reduce IOP is:", options:["Pilocarpine","Timolol (non-selective beta-blocker)","Latanoprost (prostaglandin analogue)","Dorzolamide (topical carbonic anhydrase inhibitor)"], answer:2, explanation:"Prostaglandin analogues (latanoprost, bimatoprost, travoprost) are first-line for POAG: once daily, most effective IOP reduction (~30%), good side effect profile. Timolol is traditional first-line but prostaglandins are preferred. Pilocarpine used in PACG." },

  // Ophthalmology - Cataract
  { id:6992, subject:"ENT/Ophthalmology", stem:"A patient with nuclear cataract notices improved near vision initially without reading glasses ('second sight'). This is due to:", options:["Lens becoming more transparent","Myopic shift from increased refractive index of nucleus","Presbyopia correction","Vitreous changes"], answer:1, explanation:"Nuclear sclerosis causes myopic shift (lens becomes denser, increasing refractive index → acts like a convex lens for near). Initially patient reads better ('second sight of the aged'). Later, cataract progresses and vision deteriorates for both near and far." },
  { id:6993, subject:"ENT/Ophthalmology", stem:"Posterior subcapsular cataract causes vision to be WORST in:", options:["Dim lighting conditions","Bright light (pupils constrict, maximising lens opacity effect)","Near vision only","Early morning hours"], answer:1, explanation:"PSC cataract: located at posterior pole of lens. Bright light causes miosis (pupil constriction), forcing light through the central opacity → worst vision in bright light/sunlight. Also worst for near vision. Caused by steroids, diabetes, radiation, uveitis." },
  { id:6994, subject:"ENT/Ophthalmology", stem:"Sunflower cataract (anterior capsular opacity in a sunflower pattern) is pathognomonic of:", options:["Diabetes mellitus","Wilson's disease (hepatolenticular degeneration)","Corticosteroid use","Galactosaemia"], answer:1, explanation:"Sunflower cataract (green/brown disc with petal-like peripheral spokes on anterior capsule, seen in retroillumination) is pathognomonic of Wilson's disease due to copper deposition. Galactosaemia: oil-droplet cataract. Diabetes: snowflake/true diabetic cataract." },
  { id:6995, subject:"ENT/Ophthalmology", stem:"Current gold standard surgical technique for cataract extraction with quick visual rehabilitation is:", options:["Intracapsular cataract extraction (ICCE)","Extracapsular cataract extraction (ECCE)","Phacoemulsification with IOL implant","Nd:YAG laser capsulotomy"], answer:2, explanation:"Phacoemulsification: ultrasound probe emulsifies lens through small incision (2.8mm), foldable IOL inserted. Advantages: small incision (self-sealing), quick recovery, minimal astigmatism. SICS (manual small incision) used in developing countries/hard cataracts." },

  // Ophthalmology - Retina
  { id:6996, subject:"ENT/Ophthalmology", stem:"First sign of diabetic retinopathy on fundoscopy is:", options:["Cotton wool spots","Hard exudates","Microaneurysms","Neovascularisation"], answer:2, explanation:"Microaneurysms are the earliest sign of diabetic retinopathy (NPDR). They appear as small red dots on fundoscopy, representing focal dilatations of retinal capillaries due to pericyte loss. Later: dot-blot haemorrhages, hard exudates, cotton wool spots, neovascularisation (PDR)." },
  { id:6997, subject:"ENT/Ophthalmology", stem:"Proliferative diabetic retinopathy (PDR) is characterised by:", options:["Microaneurysms and hard exudates","Cotton wool spots only","Neovascularisation of the disc or elsewhere (NVD/NVE)","Macular oedema only"], answer:2, explanation:"PDR = neovascularisation (new vessel formation on disc/elsewhere due to retinal ischaemia and VEGF release). New vessels are fragile, can bleed → vitreous haemorrhage → tractional retinal detachment → blindness. Treatment: panretinal photocoagulation (PRP) + anti-VEGF." },
  { id:6998, subject:"ENT/Ophthalmology", stem:"A patient presents with sudden onset flashes (photopsia) followed by floaters, then a 'curtain' coming across vision from one side. The MOST likely diagnosis is:", options:["Vitreous haemorrhage","Rhegmatogenous retinal detachment","Central retinal artery occlusion","ARMD (dry type)"], answer:1, explanation:"Rhegmatogenous RD (most common type): starts with posterior vitreous detachment (PVD) causing flashes → vitreous gel enters through retinal tear causing floaters → fluid lifts retina causing curtain/shadow. Emergency - needs urgent surgical repair (vitrectomy/scleral buckle)." },
  { id:6999, subject:"ENT/Ophthalmology", stem:"Drusen deposits on Bruch's membrane seen on fundoscopy indicate:", options:["Wet ARMD (choroidal neovascularisation)","Dry ARMD (age-related macular degeneration)","Diabetic maculopathy","Central serous chorioretinopathy"], answer:1, explanation:"Dry ARMD (atrophic): drusen (yellow-white deposits on Bruch's membrane under retinal pigment epithelium) + RPE atrophy. Slow progressive central visual loss. No treatment of proven benefit. Wet/exudative ARMD: choroidal neovascularisation → treated with anti-VEGF (ranibizumab/bevacizumab)." },
  { id:7000, subject:"ENT/Ophthalmology", stem:"Anti-VEGF agents used for treatment of wet age-related macular degeneration (ARMD) include:", options:["Latanoprost and timolol","Ranibizumab and bevacizumab","Acetazolamide and pilocarpine","Triamcinolone and dexamethasone"], answer:1, explanation:"Wet ARMD treatment: intravitreal anti-VEGF injections - Ranibizumab (Lucentis), Bevacizumab (Avastin, off-label), Aflibercept (Eylea), Brolucizumab. They block choroidal neovascularisation and reduce leakage, preserving/improving vision in wet ARMD." },

  // Additional ENT/Ophthalmology
  { id:7001, subject:"ENT/Ophthalmology", stem:"Otoacoustic emissions (OAE) testing is primarily used for:", options:["Diagnosing otosclerosis","Neonatal hearing screening","Assessing central auditory processing","Medicolegal hearing assessment"], answer:1, explanation:"OAE (Otoacoustic Emissions): sounds produced by the cochlea (outer hair cells) in response to stimulation. OAE present = normal cochlear function. Used for NEWBORN HEARING SCREENING (rapid, non-invasive, objective). Absent OAE: cochlear dysfunction or significant CHL." },
  { id:7002, subject:"ENT/Ophthalmology", stem:"Cholesteatoma in CSOM is best described as:", options:["Benign cyst of the middle ear","Keratinising stratified squamous epithelium in middle ear causing bone erosion","Benign tumour of ossicles","Inflammatory polyp of middle ear"], answer:1, explanation:"Cholesteatoma: accumulation of desquamating keratinising stratified squamous epithelium in middle ear/mastoid. It ERODES bone (enzymes + pressure), causing destruction of ossicles, facial canal, labyrinth, tegmen, sigmoid sinus. Treatment: surgical removal (mastoidectomy)." },
  { id:7003, subject:"ENT/Ophthalmology", stem:"Bjerrum's scotoma (arcuate scotoma) extending from blind spot around fixation is characteristic of:", options:["Retinitis pigmentosa","Glaucoma","Macular degeneration","Optic neuritis"], answer:1, explanation:"Arcuate (Bjerrum) scotoma: crescent-shaped visual field defect following the arcuate retinal nerve fibre bundle from blind spot. Pathognomonic of glaucoma (particularly POAG). Caused by damage to superior or inferior arcuate nerve fibre bundles at the optic disc." },
  { id:7004, subject:"ENT/Ophthalmology", stem:"A child presents with white pupillary reflex (leucocoria) in the right eye. The MOST important diagnosis to exclude is:", options:["Cataract","Retinoblastoma","Vitreous haemorrhage","Corneal opacity"], answer:1, explanation:"Leucocoria (white pupil/cat's eye reflex) in a child is RETINOBLASTOMA until proven otherwise - a malignant intraocular tumour of childhood. Other causes: cataract, retinopathy of prematurity, PHPV, Coats disease. Retinoblastoma is life-threatening; urgent ophthalmological evaluation essential." },
  { id:7005, subject:"ENT/Ophthalmology", stem:"Tympanoplasty type I (myringoplasty) is indicated for:", options:["Cholesteatoma with ossicular erosion","Isolated tympanic membrane perforation with intact ossicular chain","CSOM with polyp","Eustachian tube dysfunction"], answer:1, explanation:"Myringoplasty (Tympanoplasty Type I): repair of TM perforation only, with intact mobile ossicular chain. Done in inactive CSOM (tubotympanic, dry ear for ≥3 months). Uses temporalis fascia graft by underlay technique. Types II-V involve ossicular reconstruction." },

  // ── FORENSIC MEDICINE (IDs 7006–7020) ───────────────────────────────────────

  // Post-mortem Changes
  { id:7006, subject:"Forensic Medicine", stem:"Rigor mortis (post-mortem rigidity) is maximally established at:", options:["2-4 hours after death","6-12 hours after death","24-36 hours after death","48-72 hours after death"], answer:1, explanation:"Rigor mortis: starts 2-6h after death (jaw/neck first per Nysten's law), maximally established at 12h, remains rigid for 12-24h, then passes off (disappears 24-48h) in same order it appeared. Heat accelerates, cold retards onset." },
  { id:7007, subject:"Forensic Medicine", stem:"Livor mortis (post-mortem lividity) becomes FIXED (non-blanching/non-shifting) approximately:", options:["Immediately after death","1-2 hours after death","6-8 hours after death","24-36 hours after death"], answer:2, explanation:"Livor mortis (hypostasis): appears 2h post-mortem as pink/purple discolouration in dependent parts due to RBC settling. Initially blanches on pressure. Fixed (non-blanching) after 6-8h due to haemolysis + diffusion of Hb into tissues. Fixation indicates body position unchanged." },
  { id:7008, subject:"Forensic Medicine", stem:"Cherry-red colour of post-mortem lividity is seen in poisoning with:", options:["Cyanide only","Carbon monoxide only","Carbon monoxide AND cyanide","Organophosphate compounds"], answer:2, explanation:"Cherry-red/bright red lividity: Carbon monoxide (CO) and Cyanide poisoning. CO forms carboxyhaemoglobin (HbCO - cherry red). Cyanide causes histotoxic hypoxia; oxyhaemoglobin accumulates (cellular oxygen utilisation blocked) → bright red blood and lividity." },
  { id:7009, subject:"Forensic Medicine", stem:"Algor mortis (post-mortem cooling) progresses at approximately what rate after the first hour?", options:["0.5°C per hour","1°C per hour","2°C per hour","3°C per hour"], answer:1, explanation:"Algor mortis: body cools approximately 1°C per hour (after a plateau in first 1-2h due to metabolic heat). Factors affecting cooling: ambient temperature, body size, clothing, body position, wind speed. Used in Henssge nomogram for time since death estimation." },

  // Asphyxial Deaths
  { id:7010, subject:"Forensic Medicine", stem:"In hanging, the ligature mark is characteristically:", options:["Horizontal below thyroid cartilage","Oblique/inverted V-shape ABOVE thyroid cartilage","Horizontal above thyroid cartilage","Irregular with fingernail marks"], answer:1, explanation:"Hanging: ligature groove/furrow above thyroid cartilage, oblique/inverted V-shaped running upward toward the knot (non-horizontal). Pale (anaemic) margin. Throttling (manual strangulation): fingernail crescentic marks + patterned bruises over neck. Ligature strangulation: horizontal furrow below thyroid cartilage." },
  { id:7011, subject:"Forensic Medicine", stem:"The CONFIRMATORY test for death by drowning that can be performed months after burial is:", options:["Gettler test (chloride estimation)","Paltauf's haemorrhages on lung surface","Diatom test on bone marrow","Washerwoman's hands"], answer:2, explanation:"Diatom test on bone marrow: diatoms (siliceous algae) aspirated with water enter circulation, reach bone marrow (if alive at time of aspiration). Highly specific for antemortem drowning and can be detected months/years after death. Paltauf's haemorrhages and washerwoman's hands are less specific." },
  { id:7012, subject:"Forensic Medicine", stem:"Petechial haemorrhages on conjunctiva, face, and viscera (Tardieu's spots) are characteristic of:", options:["Drowning","Poisoning with CO","Asphyxial deaths (particularly throttling/strangulation)","Burns"], answer:2, explanation:"Tardieu's spots: subpleural/subpericardial petechial haemorrhages due to increased venous pressure during asphyxia. Most prominent in throttling and strangulation. Also seen on conjunctiva (subconjunctival petechiae). Pathophysiology: venous obstruction + capillary rupture due to raised intravascular pressure." },
  { id:7013, subject:"Forensic Medicine", stem:"Fracture of hyoid bone is MOST commonly associated with:", options:["Hanging","Ligature strangulation","Throttling (manual strangulation)","Smothering"], answer:2, explanation:"Hyoid bone fracture is more common in throttling (manual strangulation) than hanging. Hyoid ossifies fully by 40-60 years, so fracture more common in adults. In hanging: usually no hyoid fracture. Thyroid cartilage fracture also more common in throttling/ligature strangulation than hanging." },

  // Wound Description
  { id:7014, subject:"Forensic Medicine", stem:"An incised wound is characterised by:", options:["Irregular edges with tissue bridging","Length greater than depth with clean edges and no bridging","Depth greater than length in a boat-shaped defect","Intact skin with subcutaneous haemorrhage"], answer:1, explanation:"Incised wound (sharp cutting weapon): length > depth, clean/sharp margins, no tissue bridging, minimal bruising, copious bleeding (vessels cut cleanly), spindle/slit-shaped. Lacerated wound (blunt): irregular edges, tissue bridging (nerves/vessels survive), contaminated. Stab: depth > length." },
  { id:7015, subject:"Forensic Medicine", stem:"In gunshot wounds, which features help determine the ENTRY wound?", options:["Larger, everted, irregular stellate shape","Smaller, inverted, circular with zone of contusion/burning/tattooing depending on range","Always round regardless of range","No distinguishing features from exit wound"], answer:1, explanation:"Entry wound (gunshot): smaller, inverted edges, circular (if perpendicular), zone of burning/blackening/tattooing/contusion at close range. Exit wound: larger, everted, stellate/irregular, no fouling (no burning/tattooing), may be absent if bullet retained." },

  // Medico-legal
  { id:7016, subject:"Forensic Medicine", stem:"A dying declaration to be admissible as evidence:", options:["Must be made to a magistrate only","Must be under oath and witnessed by two doctors","Can be made to any person including doctors if magistrate unavailable; no oath required","Must be written and signed by the declarant"], answer:2, explanation:"Dying declaration: statement by a person in expectation of death about the cause/circumstances of death. Valid if made to magistrate (preferable) OR any person including a doctor if magistrate unavailable. No oath required (Section 32, Indian Evidence Act). Must be voluntary + declarant in lucid state. Doctor should record condition of patient." },
  { id:7017, subject:"Forensic Medicine", stem:"Section 174 of CrPC (Code of Criminal Procedure) requires police inquest for:", options:["All natural deaths","Unnatural deaths (drowning, suicide, accidents, unknown cause)","Medico-legal cases only","Deaths in hospitals only"], answer:1, explanation:"Section 174 CrPC: police inquest is mandatory for all unnatural/suspicious deaths including drowning, suicide, accidents, deaths by violence, unknown cause, or any death in suspicious circumstances. Magistrate inquest (Section 176) for deaths in custody. Doctor's role: determine cause of death." },
  { id:7018, subject:"Forensic Medicine", stem:"A Medico-legal Case (MLC) is BEST defined as:", options:["Any case requiring hospitalization","Any case where police FIR has been registered","Any case where injuries, poisoning, or death may have legal implications requiring documentation","Only homicide cases"], answer:2, explanation:"MLC = any case where injuries, acts, or omissions have legal implications (criminal, civil). Includes: assault, rape, poisoning, road traffic accidents, industrial accidents, suspected non-accidental injuries, deaths, burns. Doctor must document carefully, inform police, and preserve evidence." },
  { id:7019, subject:"Forensic Medicine", stem:"Post-mortem staining (lividity) brown in colour is seen in poisoning with:", options:["Carbon monoxide","Cyanide","Nitrites/methaemoglobin-forming substances","Hydrogen sulphide"], answer:2, explanation:"Brownish/chocolate-coloured lividity and blood = methaemoglobinaemia (caused by nitrites, dapsone, aniline, phenacetin). Cherry red = CO + cyanide. Bluish-grey = sulphaemoglobin (hydrogen sulphide, dapsone). Bright red = cyanide (oxidised haemoglobin)." },
  { id:7020, subject:"Forensic Medicine", stem:"Inquest in forensic medicine is an inquiry into:", options:["Nature and extent of injuries only","Cause and manner of unnatural/suspicious death","Mental capacity of the accused","Drug intoxication levels in blood"], answer:1, explanation:"Inquest = formal inquiry into the CAUSE and MANNER (circumstances) of an unnatural/suspicious death. Types: Police inquest (Sec 174 CrPC - most common), Magistrate inquest (Sec 176 - deaths in custody/rape deaths), Coroner's inquest (Mumbai only in India). Purpose: establish identity, cause, manner, and time of death." },
];
